targets.expr:
sum(rate(zeebe_executed_instances_total{action="completed", namespace=~"$namespace", type="ROOT_PROCESS_INSTANCE"}[$__rate_interval])) by (namespace)
/
(sum(rate(grpc_server_processing_duration_seconds_count{namespace=~"$namespace", method="CreateProcessInstance"}[$__rate_interval])) by (namespace)
or
sum(rate(http_server_requests_seconds_count{
    method="POST",
    namespace=~"$namespace",
    uri="/v2/process-instances",
  }[$__rate_interval]) != 0) by(namespace)
)

sum by(uri, method) (
  rate(http_server_requests_seconds_count{
    method!~"GET|OPTIONS|HEAD",
    namespace=~"$namespace",
    uri!~"^/actuator/health(/.*)?$|^/actuator/prometheus$|.*/mcp.*",
    uri!~".*/search.*|.*/statistics.*",
  }[$__rate_interval]) != 0
)

sum by(uri, method) (
